		privateIPBlocks = append(privateIPBlocks, block)
	}
}

// isPrivateIP checks if an IP address is in private ranges
func isPrivateIP(ip net.IP) bool {
	for _, block := range privateIPBlocks {
		if block.Contains(ip) {
			return true
		}
	}
	return false
}

// resolveAndCheckHost resolves hostname and checks for private IPs
func resolveAndCheckHost(host string) error {
	// First check if it's an IP address
	if ip := net.ParseIP(host); ip != nil {
		if isPrivateIP(ip) {
			return fmt.Errorf("access to private IPs not allowed")
		}
		return nil
	}

	// Resolve hostname
	ctx, cancel := context.WithTimeout(context.Background(), 3*time.Second)
	defer cancel()

	addrs, err := net.DefaultResolver.LookupIPAddr(ctx, host)
	if err != nil {
		return fmt.Errorf("failed to resolve hostname: %v", err)
	}

	// Check all resolved IPs
	for _, addr := range addrs {
		if isPrivateIP(addr.IP) {
			return fmt.Errorf("host resolves to private IP: %s", addr.IP)
		}
	}

	return nil
}

