)

// Request body
type PreviewRequest struct {
	URL string `json:"url"`
}

// Response body
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
}

// Helper function to validate host for SSRF protection
func isSafeHost(host string, ctx context.Context) bool {
	// Check if host is an IP address
	if ip := net.ParseIP(host); ip != nil {
		if ip.IsPrivate() || ip.IsLoopback() {
			return false
		}
		return true
	}

	// Resolve domain name to IP addresses
	resolver := net.DefaultResolver
	ips, err := resolver.LookupIPAddr(ctx, host)
	if err != nil {
		// If resolution fails, treat as unsafe
		return false
	}

	for _, ipAddr := range ips {
		ip := ipAddr.IP
		if ip.IsPrivate() || ip.IsLoopback() {
			return false
		}
	}
	return true
}

func FetchURLPreview(ctx echo.Context) error {
	req := new(PreviewRequest)
