	resp, err := client.Do(httpReq)
	if err != nil {
		return c.JSON(http.StatusBadRequest, PreviewResponse{
			Error: fmt.Sprintf("Failed to fetch URL: %v", err),
		})
	}
	defer resp.Body.Close()

	// Check for successful response
	if resp.StatusCode != http.StatusOK {
		return c.JSON(http.StatusBadRequest, PreviewResponse{
			Error: fmt.Sprintf("HTTP error: %s", resp.Status),
		})
	}

	// Check content type
	contentType := resp.Header.Get("Content-Type")
	if !strings.Contains(contentType, "text/html") {
		return c.JSON(http.StatusBadRequest, PreviewResponse{
			Error: "URL does not return HTML content",
		})
	}

	// Read response body
	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return c.JSON(http.StatusInternalServerError, PreviewResponse{
			Error: fmt.Sprintf("Failed to read response: %v", err),
		})
	}

	// Parse HTML to extract title and meta description
	title, description := parseHTML(string(body))

	return c.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// parseHTML extracts title and meta description from HTML content
func parseHTML(htmlContent string) (string, string) {
	var title, description string

	// Parse HTML
	doc, err := html.Parse(strings.NewReader(htmlContent))
	if err != nil {
		return "", ""
	}

	// Recursive function to traverse HTML nodes
	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		// Extract title from <title> tag
		if n.Type == html.ElementNode && n.Data == "title" && n.FirstChild != nil {
			title = n.FirstChild.Data
		}

		// Extract description from <meta name="description"> tag
		if n.Type == html.ElementNode && n.Data == "meta" {
			var name, content string
			for _, attr := range n.Attr {
				if attr.Key == "name" {
					name = attr.Val
				}
				if attr.Key == "content" {
					content = attr.Val
				}
			}
			if strings.ToLower(name) == "description" && content != "" {
				description = content
			}
		}

		// Continue traversing child nodes
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)
	return title, description
}

func main() {
	// Create Echo instance
	e := echo.New()

	// Register route
	e.POST("/preview", FetchURLPreview)

	// Start server
	e.Logger.Fatal(e.Start(":8080"))
}

