// FetchURLPreview handles POST requests to /preview
func FetchURLPreview(ctx echo.Context) error {
	var req PreviewRequest
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, PreviewResponse{
			Error: "Invalid JSON request body",
		})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, PreviewResponse{
			Error: "URL field is required",
		})
	}

	// Add scheme if missing
	if !strings.HasPrefix(req.URL, "http://") && !strings.HasPrefix(req.URL, "https://") {
		req.URL = "https://" + req.URL
	}

	// Create HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Create request with context timeout
	httpReq, err := http.NewRequestWithContext(context.Background(), "GET", req.URL, nil)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, PreviewResponse{
			Error: fmt.Sprintf("Invalid URL: %v", err),
		})
	}

	// Set user agent to avoid being blocked
	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	// Fetch the URL
	resp, err := client.Do(httpReq)
	if err != nil {
		if errors.Is(err, context.DeadlineExceeded) {
			return ctx.JSON(http.StatusRequestTimeout, PreviewResponse{
				Error: "Request timeout: took longer than 3 seconds",
			})
		}
		return ctx.JSON(http.StatusBadRequest, PreviewResponse{
			Error: fmt.Sprintf("Failed to fetch URL: %v", err),
		})
	}
	defer resp.Body.Close()

	// Check response status
	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadRequest, PreviewResponse{
			Error: fmt.Sprintf("HTTP error: %s", resp.Status),
		})
	}

	// Check content type
	contentType := resp.Header.Get("Content-Type")
	if !strings.Contains(contentType, "text/html") {
		return ctx.JSON(http.StatusBadRequest, PreviewResponse{
			Error: "URL does not return HTML content",
		})
	}

	// Parse HTML
	title, description, err := parseHTML(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, PreviewResponse{
			Error: fmt.Sprintf("Failed to parse HTML: %v", err),
		})
	}

	// Return successful response
	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// parseHTML extracts title and meta description from HTML content
func parseHTML(body io.Reader) (title, description string, err error) {
	doc, err := html.Parse(body)
	if err != nil {
		return "", "", err
	}

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
