// Request represents the JSON payload for the /preview endpoint
type Request struct {
	URL string `json:"url"`
}

// Response represents the JSON response from the /preview endpoint
type Response struct {
	Title       string `json:"title"`
	Description string `json:"description"`
	Error       string `json:"error,omitempty"`
}

// FetchURLPreview handles POST requests to /preview and returns page metadata
func FetchURLPreview(ctx echo.Context) error {
	var req Request
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, Response{
			Error: "Invalid JSON payload",
		})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, Response{
			Error: "URL field is required",
		})
	}

	// Create HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Create request with context timeout
	httpReq, err := http.NewRequestWithContext(context.Background(), "GET", req.URL, nil)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, Response{
			Error: fmt.Sprintf("Invalid URL: %v", err),
		})
	}

	// Set user agent to avoid being blocked by some sites
	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	// Fetch the URL
	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, Response{
			Error: fmt.Sprintf("Failed to fetch URL: %v", err),
		})
	}
	defer resp.Body.Close()

	// Check for successful response
	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadRequest, Response{
			Error: fmt.Sprintf("HTTP error: %s", resp.Status),
		})
	}

	// Check content type
	contentType := resp.Header.Get("Content-Type")
	if !strings.Contains(contentType, "text/html") {
		return ctx.JSON(http.StatusBadRequest, Response{
			Error: "URL does not return HTML content",
		})
	}

	// Parse HTML to extract title and description
	title, description, err := parseHTML(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, Response{
			Error: fmt.Sprintf("Failed to parse HTML: %v", err),
		})
	}

	return ctx.JSON(http.StatusOK, Response{
		Title:       title,
		Description: description,
	})
}

// parseHTML extracts title and meta description from HTML content
func parseHTML(r io.Reader) (string, string, error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", err
	}

	var title, description string

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			switch n.Data {
			case "title":
				if n.FirstChild != nil {
					title = n.FirstChild.Data
				}
			case "meta":
				var name, content string
				for _, attr := range n.Attr {
					switch attr.Key {
					case "name":
						name = attr.Val
					case "content":
						content = attr.Val
					}
				}
				if strings.ToLower(name) == "description" && content != "" {
					description = content
				}
			}
		}

		// Stop traversing if we found both title and description
		if title != "" && description != "" {
			return
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
			if title != "" && description != "" {
				return
			}
		}
	}

	traverse(doc)
	return title, description, nil
}

func main() {
	e := echo.New()

	// Middleware
	e.Use(middleware.Logger())
	e.Use(middleware.Recover())
	e.Use(middleware.CORS())

	// Routes
	e.POST("/preview", FetchURLPreview)

	// Start server
	e.Logger.Fatal(e.Start(":8080"))
}

