package main

import (
	"fmt"
	"io"
	"net"
	"net/http"
	"net/url"
	"strings"
	"time"

	"github.com/labstack/echo/v4"
	"golang.org/x/net/html"
)

// Request body
type PreviewRequest struct {
	URL string `json:"url"`
}

// Response body
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
}

func isSafeURL(u *url.URL) bool {
	host := u.Hostname()

	// Check if host is an IP address
	if ip := net.ParseIP(host); ip != nil {
		// Deny private and loopback IPs
		if ip.IsPrivate() || ip.IsLoopback() {
			return false
		}
		return true
	}

	// Deny localhost and internal domains
	lowerHost := strings.ToLower(host)
	if strings.HasSuffix(lowerHost, ".local") ||
		strings.HasSuffix(lowerHost, ".internal") ||
		strings.Contains(lowerHost, "localhost") ||
		strings.Contains(lowerHost, "127.0.0.1") ||
		strings.Contains(lowerHost, "::1") ||
		strings.Contains(lowerHost, "0.0.0.0") ||
		strings.Contains(lowerHost, "[::]") {
		return false
	}

	return true
}

func FetchURLPreview(ctx echo.Context) error {
	req := new(PreviewRequest)
	if err := ctx.Bind(req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON"})
	}

	// Validate URL
	parsedURL, err := url.Parse(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL format"})
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Only HTTP/HTTPS URLs are allowed"})
	}

	// SSRF protection - check for unsafe URLs
	if !isSafeURL(parsedURL) {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Access to internal resources is not allowed"})
	}

	// Fetch the URL with timeout
	client := &http.Client{
		Timeout: 5 * time.Second,
		Transport: &http.Transport{
			DialContext: (&net.Dialer{
				Timeout: 5 * time.Second,
			}).DialContext,
			TLSHandshakeTimeout: 5 * time.Second,
			ResponseHeaderTimeout: 5 * time.Second,
			ExpectContinueTimeout: 1 * time.Second,
			MaxIdleConns: 10,
			IdleConnTimeout: 30 * time.Second,
		},
	}

	httpReq, err := http.NewRequestWithContext(ctx.Request().Context(), http.MethodGet, parsedURL.String(), nil)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to create request"})
	}
	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")
	httpReq.Header.Set("Accept", "text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8")

	resp, err := client.Do(httpReq)
	if err != nil {
		if strings.Contains(err.Error(), "timeout") || strings.Contains(err.Error(), "deadline") {
			return ctx.JSON(http.StatusRequestTimeout, map[string]string{"error": "Request timeout"})
		}
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(resp.StatusCode, map[string]string{"error": fmt.Sprintf("HTTP %d", resp.StatusCode)})
	}

	// Check content type
	contentType := resp.Header.Get("Content-Type")
	if !strings.Contains(contentType, "text/html") {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL does not return HTML content"})
	}

	// Limit response size to prevent DoS
	body, err := io.ReadAll(io.LimitReader(resp.Body, 1024*1024)) // 1MB limit
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response body"})
	}

	title, description := extractTitleAndDescription(body)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

func extractTitleAndDescription(htmlContent []byte) (string, string) {
	var title, description string

	doc, err := html.Parse(strings.NewReader(string(htmlContent)))
	if err != nil {
		return "", ""
	}

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract title
			if n.Data == "title" && n.FirstChild != nil && title == "" {
				title = n.FirstChild.Data
			}

			// Extract meta description
			if n.Data == "meta" {
				var name, content, property string
				for _, attr := range n.Attr {
					switch attr.Key {
					case "name":
						name = attr.Val
					case "content":
						content = attr.Val
					case "property":
						property = attr.Val
					}
				}

				if name == "description" && content != "" && description == "" {
					description = content
				}

				// Also check for og:description as fallback
				if property == "og:description" && content != "" && description == "" {
					description = content
				}
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)

	// Trim whitespace
	title = strings.TrimSpace(title)
	description = strings.TrimSpace(description)

	// Limit length for safety
	if len(title) > 200 {
		title = title[:200] + "..."
	}
	if len(description) > 300 {
		description = description[:300] + "..."
	}

	return title, description
}

func main() {
