		})
	}

	// Return successful response
	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// extractMetadata parses HTML to find title and meta description
func extractMetadata(htmlContent io.Reader) (string, string, error) {
	doc, err := html.Parse(htmlContent)
	if err != nil {
