				}
				if attr.Key == "content" {
					content = attr.Val
				}
			}
			if metaName == "description" && content != "" {
				description = strings.TrimSpace(content)
			}
		}

		// Continue traversing child nodes
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}
	traverse(doc)

	return title, description, nil
}

