)

// Request structure for JSON input
type PreviewRequest struct {
	URL string `json:"url" validate:"required,url"`
}

// Response structure for JSON output
type PreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
	Error       string `json:"error,omitempty"`
}

// FetchURLPreview handles POST requests to /preview
func FetchURLPreview(ctx echo.Context) error {
	var req PreviewRequest

	// Parse and validate request body
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, PreviewResponse{
			Error: "Invalid JSON format",
		})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, PreviewResponse{
			Error: "URL is required",
		})
	}

	// Create HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Create request with context
	httpReq, err := http.NewRequestWithContext(ctx.Request().Context(), "GET", req.URL, nil)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, PreviewResponse{
			Error: "Invalid URL",
		})
	}

	// Set user agent to avoid being blocked
	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	// Fetch the URL
	resp, err := client.Do(httpReq)
	if err != nil {
		if errors.Is(err, context.DeadlineExceeded) {
			return ctx.JSON(http.StatusRequestTimeout, PreviewResponse{
				Error: "Request timeout: took longer than 3 seconds",
			})
		}
		return ctx.JSON(http.StatusBadRequest, PreviewResponse{
			Error: "Failed to fetch URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Check for successful response
	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadRequest, PreviewResponse{
			Error: "HTTP error: " + resp.Status,
		})
	}

	// Check content type
	contentType := resp.Header.Get("Content-Type")
	if !strings.Contains(contentType, "text/html") {
		return ctx.JSON(http.StatusBadRequest, PreviewResponse{
			Error: "URL does not return HTML content",
		})
	}

	// Parse HTML to extract title and description
	title, description, err := parseHTML(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, PreviewResponse{
			Error: "Failed to parse HTML: " + err.Error(),
		})
	}

	// Return successful response
	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// parseHTML extracts title and meta description from HTML content
func parseHTML(body io.Reader) (string, string, error) {
	doc, err := html.Parse(body)
	if err != nil {
		return "", "", err
	}

	var title, description string

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract title from <title> tag
			if n.Data == "title" && n.FirstChild != nil {
				title = n.FirstChild.Data
			}

			// Extract description from <meta name="description"> tag
			if n.Data == "meta" {
				var name, content string
				for _, attr := range n.Attr {
					if attr.Key == "name" {
						name = attr.Val
					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}
				if name == "description" && content != "" {
					description = content
				}
			}
		}

		// Continue traversing child nodes
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)

	// Trim whitespace
	title = strings.TrimSpace(title)
	description = strings.TrimSpace(description)

	return title, description, nil
}

func main() {
	// Create Echo instance
	e := echo.New()

	// Middleware
	e.Use(middleware.Logger())
	e.Use(middleware.Recover())
	e.Use(middleware.CORS())

	// Register route
	e.POST("/preview", FetchURLPreview)

	// Start server
	e.Logger.Fatal(e.Start(":8080"))
}

